function useIV(o={}){
  const r=useRef(null),[v,sv]=useState(false);
  useEffect(()=>{
    const ob=new IntersectionObserver(([e])=>{if(e.isIntersecting){sv(true);ob.disconnect();}},{threshold:.1,...o});
    if(r.current)ob.observe(r.current);
    return()=>ob.disconnect();
  },[]);
  return[r,v];
}
function FI({children,d=0,style={}}){
  const[r,v]=useIV();
  return <div ref={r} style={{opacity:v?1:0,transform:v?"translateY(0)":"translateY(26px)",transition:`opacity .65s ease ${d}s,transform .65s ease ${d}s`,...style}}>{children}</div>;
}

function SS({slides}){
  const[cur,sc]=useState(0),[fad,sf]=useState(false);
  const tr=useRef(null);
  const tot=slides.length;
  const gt=(i)=>{if(fad||i===cur)return;sf(true);setTimeout(()=>{sc(i);sf(false);},320);};
  const go=(d)=>gt((cur+d+tot)%tot);
  const rg=(fn)=>{clearInterval(tr.current);fn();tr.current=setInterval(()=>go(1),5200);};
  useEffect(()=>{tr.current=setInterval(()=>go(1),5200);return()=>clearInterval(tr.current);},[cur]);
  return(
    <div>
      <div style={{position:"relative",lineHeight:0,overflow:"hidden"}}>
        <img src={slides[cur]} alt="slide" style={{width:"100%",display:"block",height:"auto",maxHeight:"clamp(260px,45vw,520px)",minHeight:200,objectFit:"cover",objectPosition:"center top",opacity:fad?0:1,transition:"opacity .32s ease"}}/>
        <div style={{position:"absolute",bottom:0,left:0,right:0,height:64,background:"linear-gradient(to top,rgba(6,5,4,.65),transparent)",pointerEvents:"none"}}/>
        <div style={{position:"absolute",bottom:16,right:20,fontFamily:"Montserrat,sans-serif",fontSize:13,color:"rgba(201,168,76,.85)",letterSpacing:".1em"}}>{String(cur+1).padStart(2,"0")}/{String(tot).padStart(2,"0")}</div>
        {[-1,1].map(d=>(<button key={d} onClick={()=>rg(()=>go(d))} style={{position:"absolute",top:"50%",[d===-1?"left":"right"]:16,transform:"translateY(-50%)",width:42,height:42,borderRadius:"50%",border:"1px solid rgba(201,168,76,.45)",background:"rgba(6,5,4,.5)",color:"#c9a84c",fontSize:20,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",backdropFilter:"blur(4px)",transition:"all .2s"}} onMouseEnter={e=>e.currentTarget.style.background="rgba(201,168,76,.18)"} onMouseLeave={e=>e.currentTarget.style.background="rgba(6,5,4,.5)"}>{d===-1?"‹":"›"}</button>))}
      </div>
      <div style={{display:"flex",background:DARK}}>
        {slides.map((s,i)=>(<button key={i} onClick={()=>rg(()=>gt(i))} style={{flex:1,padding:0,border:"none",cursor:"pointer",position:"relative",lineHeight:0,opacity:i===cur?1:.35,transition:"opacity .22s",outline:"none"}}><img src={s} alt="" style={{width:"100%",height:"clamp(44px,6vw,62px)",objectFit:"cover",objectPosition:"center top",display:"block"}}/>{i===cur&&<div style={{position:"absolute",bottom:0,left:0,right:0,height:3,background:"#c9a84c"}}/>}</button>))}
      </div>
      <div style={{height:2,background:"rgba(201,168,76,.1)"}}><div style={{height:"100%",background:"#c9a84c",width:((cur+1)/tot*100)+"%",transition:"width .4s ease"}}/></div>
    </div>
  );
}

