function Nav({page,sp}){
  const[sc,ss]=useState(false);
  const[mo,smo]=useState(false);
  useEffect(()=>{const fn=()=>ss(window.scrollY>40);window.addEventListener("scroll",fn);return()=>window.removeEventListener("scroll",fn);},[]);
  const links=[["home","Home"],["about","About Us"],["products","Products"],["contact","Contact"]];
  return(
    <nav className="main-nav" style={{position:"sticky",top:0,zIndex:200,background:sc||mo?"rgba(255,252,246,.98)":"rgba(255,255,255,.97)",borderBottom:`1px solid ${sc?"rgba(201,168,76,.3)":"rgba(201,168,76,.15)"}`,padding:"0 48px",display:"flex",alignItems:"center",justifyContent:"space-between",height:74,transition:"background .3s",boxShadow:sc?"0 4px 24px rgba(0,0,0,.1),0 1px 0 rgba(201,168,76,.2)":"0 1px 0 rgba(201,168,76,.1)",backdropFilter:"blur(12px)"}}>
      <button onClick={()=>{sp("home");smo(false);}} style={{background:"none",border:"none",cursor:"pointer",padding:0}}><Logo/></button>
      <button className="ham" onClick={()=>smo(!mo)}>☰</button>
      <ul className={`nlw ${mo?"open":""}`} style={{display:"flex",listStyle:"none",gap:36,alignItems:"center"}}>
        {links.map(([pg,lbl])=>(<li key={lbl}><button className={`nl${lbl==="Contact"?" cta":""} ${page===pg&&lbl!=="Contact"?" active":""}`} onClick={()=>{sp(pg);smo(false);}}>{lbl}</button></li>))}
      </ul>
    </nav>
  );
}
