              <div style={{fontSize:10,letterSpacing:".27em",textTransform:"uppercase",color:"#c9a84c",marginBottom:14,display:"flex",alignItems:"center",gap:12}}><span style={{display:"block",width:26,height:1,background:"#c9a84c"}}/>Marine Product Line</div>
